const body = $input.first().json.body || $input.first().json;
if (!body.title) return [{ json: { error: true, message: 'Missing title' } }];

const storeUrl = body.etsy_url || body.gumroad_url || body.payhip_url || '#';

return [{ json: {
  product_id: body.product_id || `prod_${Date.now()}`,
  title: body.title,
  description: body.description || '',
  category: body.category || 'productivity',
  brand_id: body.brand_id || 'clearstack',
  keywords: body.keywords || [],
  primary_keyword: (body.keywords || [])[0] || body.title,
  price: body.price || 9.99,
  store_url: storeUrl,
  store_urls: {
    etsy: body.etsy_url || '',
    gumroad: body.gumroad_url || '',
    payhip: body.payhip_url || ''
  },
  cover_image: body.cover_image || '',
  brand_name: 'ClearStack Studio',
  brand_color_primary: '#1B2A4A',
  brand_color_accent: '#C9A84C',
  work_dir: `/tmp/video_${body.product_id || Date.now()}`,
  avatar_enabled: body.avatar_enabled || false,
  _received_at: new Date().toISOString()
}}];

// Parse mistral scripts output
const raw = $input.first().json;
const product = $('⚙️ Validate + Build Video Context').first().json;

let scriptData;
try {
  const content = raw?.message?.content || raw?.response || '';
  const match = content.match(/```json\n?([\s\S]*?)\n?```/) || content.match(/({[\s\S]*})/);
  scriptData = JSON.parse((match ? match[1] || match[0] : content).trim());
} catch(e) {
  // Fallback scripts if parse fails
  scriptData = {
    videos: [
      {
        video_id: 'text_overlay_15s',
        format: 'TEXT_OVERLAY_15S',
        platform: 'tiktok_reels',
        duration_seconds: 15,
        hook_words: 'Stop scrolling.',
        scenes: [
          { scene_number: 1, timestamp_start: 0, timestamp_end: 4, text_overlay: 'Stop scrolling.', subtext: 'This will change how you work.', position: 'center', background: 'navy' },
          { scene_number: 2, timestamp_start: 4, timestamp_end: 9, text_overlay: product.title, subtext: 'The template you\'ve been looking for.', position: 'center', background: 'navy' },
          { scene_number: 3, timestamp_start: 9, timestamp_end: 15, text_overlay: 'Link in bio ↑', subtext: `Only $${product.price}`, position: 'center', background: 'navy' }
        ],
        caption_tiktok: `You need this 👀 #productivity #template #digitalproduct`,
        caption_reels: `Working smarter, not harder — this template does the heavy lifting ✨ Link in bio!`,
        caption_shorts: product.title,
        voiceover_script: null
      }
    ],
    music_mood: 'upbeat_focus'
  };
}

// Separate text-overlay videos from avatar video
const allVideos = scriptData.videos || [];
const textVideos = allVideos.filter(v => v.format !== 'UGC_AVATAR_60S');
const avatarVideo = allVideos.find(v => v.format === 'UGC_AVATAR_60S') || null;

return [{ json: {
  ...product,
  script_data: scriptData,
  text_videos: textVideos,
  avatar_video: avatarVideo,
  music_mood: scriptData.music_mood || 'upbeat_focus',
  posting_strategy: scriptData.posting_strategy || {},
  _scripts_parsed: true
}}];

// Combine setup results + parsed scripts
const setupResult = $('💻 Setup Video Environment').first().json;
const scripts = $input.first().json;

const setupStdout = setupResult.stdout || '';
const workDir = scripts.work_dir;
const coverReady = setupStdout.includes('COVER_READY');
const setupDone = setupStdout.includes('SETUP_DONE');

return [{ json: {
  ...scripts,
  work_dir: workDir,
  cover_ready: coverReady,
  cover_path: coverReady ? `${workDir}/cover_resized.jpg` : null,
  bg_vertical: `${workDir}/bg_vertical.png`,
  bg_square: `${workDir}/bg_square.png`,
  setup_ok: setupDone
}}];

// Build complete FFmpeg commands for all text-overlay videos
const data = $input.first().json;
const workDir = data.work_dir;
const P = (data.brand_color_primary || '#1B2A4A').replace('#', '0x');
const A = (data.brand_color_accent || '#C9A84C').replace('#', '0x');
const W = '0xFFFFFF';
const textVideos = data.text_videos || [];
const coverPath = data.cover_path;
const bgVertical = data.bg_vertical;

// Helper: escape text for FFmpeg drawtext
const escText = (t) => (t || '').replace(/'/g, "'\\''").replace(/:/g, '\\:').replace(/,/g, '\\,').substring(0, 50);

// Helper: build fade filter for a text element
const fadeFilter = (t0, t1) =>
  `alpha='if(lt(t,${t0}),0,if(lt(t,${t0+0.4}),(t-${t0})/0.4,if(lt(t,${t1-0.3}),1,max(0,(${t1}-t)/0.3))))'`;

const commands = [];

for (const video of textVideos) {
  const outputFile = `${workDir}/${video.video_id}.mp4`;
  const duration = video.duration_seconds || 15;
  const scenes = video.scenes || [];
  const format = video.format || 'TEXT_OVERLAY_15S';

  // Font path — try multiple options
  const font = '/usr/share/fonts/truetype/open-sans/OpenSans-Bold.ttf';
  const fontFallback = '/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf';

  if (format === 'PRODUCT_REVEAL_15S' && coverPath) {
    // Product reveal: cover zoom + text
    const textFilters = scenes.map(s => {
      const mainText = escText(s.text_overlay);
      const fade = fadeFilter(s.timestamp_start, s.timestamp_end);
      return `drawtext=text='${mainText}':fontsize=64:fontcolor=${W}:x=(w-text_w)/2:y=(h-text_h)/2-40:enable='between(t,${s.timestamp_start},${s.timestamp_end})':${fade}:shadowcolor=0x000000:shadowx=2:shadowy=2`;
    }).join(',');

    commands.push({
      video_id: video.video_id,
      format,
      platform: video.platform,
      duration,
      command: `ffmpeg -y -loop 1 -i ${coverPath} -vf "scale=1080:1920:force_original_aspect_ratio=increase,crop=1080:1920,zoompan=z='min(zoom+0.002,1.3)':x='iw/2-(iw/zoom/2)':y='ih/2-(ih/zoom/2)':d=${duration*30}:s=1080x1920,setsar=1,drawbox=x=0:y=0:w=1080:h=7:color=${A}:t=fill,${textFilters}" -c:v libx264 -t ${duration} -r 30 -pix_fmt yuv420p -crf 22 -preset fast ${outputFile}`,
      output_file: outputFile,
      caption_tiktok: video.caption_tiktok,
      caption_reels: video.caption_reels,
      caption_shorts: video.caption_shorts,
      has_voiceover: false
    });

  } else {
    // Text-overlay on navy background
    const textFilters = scenes.map(s => {
      const mainText = escText(s.text_overlay);
      const subText = s.subtext ? escText(s.subtext) : null;
      const fade = fadeFilter(s.timestamp_start, s.timestamp_end);
      const yMain = s.position === 'top' ? '200' : s.position === 'bottom' ? 'h-300' : '(h-text_h)/2-60';
      const ySub = s.position === 'top' ? '340' : s.position === 'bottom' ? 'h-200' : '(h-text_h)/2+100';
      const isAccent = s.text_overlay?.includes('✓') || s.text_overlay?.includes('→');
      const mainColor = isAccent ? A : W;
      const fontSize = mainText.length > 25 ? 56 : 72;

      let filter = `drawtext=text='${mainText}':fontfile=${font}:fontsize=${fontSize}:fontcolor=${mainColor}:x=(w-text_w)/2:y=${yMain}:enable='between(t,${s.timestamp_start},${s.timestamp_end})':${fade}:shadowcolor=0x00000088:shadowx=3:shadowy=3`;
      if (subText) {
        const fadeSub = fadeFilter(s.timestamp_start + 0.2, s.timestamp_end);
        filter += `,drawtext=text='${subText}':fontfile=${fontFallback}:fontsize=38:fontcolor=0xFFFFFFBB:x=(w-text_w)/2:y=${ySub}:enable='between(t,${s.timestamp_start},${s.timestamp_end})':${fadeSub}`;
      }
      return filter;
    }).join(',');

    // Brand bar + accent line + text filters
    const fullFilter = `scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2:${P},drawbox=x=0:y=0:w=1080:h=7:color=${A}:t=fill,drawbox=x=0:y=1913:w=1080:h=7:color=${A}:t=fill,${textFilters}`;

    commands.push({
      video_id: video.video_id,
      format,
      platform: video.platform,
      duration,
      command: `ffmpeg -y -loop 1 -i ${bgVertical} -vf "${fullFilter}" -c:v libx264 -t ${duration} -r 30 -pix_fmt yuv420p -crf 22 -preset fast ${outputFile}`,
      output_file: outputFile,
      caption_tiktok: video.caption_tiktok,
      caption_reels: video.caption_reels,
      caption_shorts: video.caption_shorts,
      has_voiceover: false
    });
  }
}

return commands.map(cmd => ({ json: { ...data, video_job: cmd } }));

// Prepare voiceover generation for videos that need it
// Checks which videos have voiceover scripts
const data = $input.first().json;
const textVideos = data.text_videos || [];

// Find videos that need voiceover (tips/countdown style)
const voiceoverVideos = textVideos.filter(v =>
  v.voiceover_script && v.voiceover_script.length > 10
);

if (voiceoverVideos.length === 0) {
  // No voiceovers needed — pass through
  return [{ json: { ...data, voiceovers: [], voiceover_needed: false } }];
}

return voiceoverVideos.map(v => ({ json: {
  ...data,
  voiceover_target_video_id: v.video_id,
  voiceover_script: v.voiceover_script,
  voiceover_needed: true,
  voice_style: 'calm_professional'
}}));

// Determine voiceover file path and pass to video merger
const piperResult = $('🎤 Piper TTS — Generate Voiceover (Free)').first().json;
const videoContext = $('⚙️ Prep Voiceover Jobs').first().json;

const stdout = piperResult.stdout || '';
const piperSuccess = stdout.includes('PIPER_SUCCESS');
const piperPath = piperSuccess ? stdout.split('|')[1]?.trim() : null;

return [{ json: {
  ...videoContext,
  voiceover_path: piperPath,
  voiceover_source: piperSuccess ? 'piper' : 'elevenlabs_needed',
  _voiceover_ready: piperSuccess
}}];

// Collect all rendered video results
const product = $('⚙️ Validate + Build Video Context').first().json;
const workDir = product.work_dir;
const scriptData = $('⚙️ Parse Video Scripts').first().json;
const allVideos = scriptData.text_videos || [];

// Check which files exist and build results
const results = allVideos.map(v => {
  const voicedPath = `${workDir}/${v.video_id}_voiced.mp4`;
  const plainPath = `${workDir}/${v.video_id}.mp4`;
  return {
    video_id: v.video_id,
    format: v.format,
    platform: v.platform,
    // Prefer voiced version if it exists
    file_path: voicedPath, // Will fall back to plain in upload node
    plain_path: plainPath,
    duration: v.duration_seconds,
    caption_tiktok: v.caption_tiktok || '',
    caption_reels: v.caption_reels || '',
    caption_shorts: v.caption_shorts || '',
    has_voiceover: !!v.voiceover_script
  };
});

// Check avatar
const avatarVideo = scriptData.avatar_video;
const avatarPath = `${workDir}/avatar_final.mp4`;

return [{ json: {
  product_id: product.product_id,
  product_title: product.title,
  work_dir: workDir,
  store_url: product.store_url,
  brand_id: product.brand_id,
  videos: results,
  avatar_video: avatarVideo ? {
    file_path: avatarPath,
    script: avatarVideo.voiceover_script,
    caption_tiktok: avatarVideo.caption_tiktok,
    caption_reels: avatarVideo.caption_reels,
    caption_shorts: avatarVideo.caption_shorts
  } : null,
  music_mood: scriptData.music_mood,
  posting_strategy: scriptData.posting_strategy,
  _collected: true
}}];

// Build platform-specific post payloads from all videos
const data = $input.first().json;
const videos = data.videos || [];
const avatarVideo = data.avatar_video;
const brandConfig = {}; // Would pull from WF06

const posts = [];

// TikTok posts (text-overlay 15s + 30s + avatar)
const tiktokVideos = [...videos.filter(v => v.platform?.includes('tiktok')), avatarVideo].filter(Boolean);
tiktokVideos.forEach(v => posts.push({
  platform: 'tiktok',
  video_path: v.file_path,
  caption: v.caption_tiktok || '',
  schedule: data.posting_strategy?.best_time_tiktok || '19:00'
}));

// Instagram Reels
const reelsVideos = [...videos.filter(v => v.platform?.includes('reels')), avatarVideo].filter(Boolean);
reelsVideos.forEach(v => posts.push({
  platform: 'instagram_reels',
  video_path: v.file_path,
  caption: v.caption_reels || '',
  schedule: data.posting_strategy?.best_time_reels || '18:00'
}));

// YouTube Shorts
const shortsVideos = videos.filter(v => v.format === 'PRODUCT_REVEAL_15S' || v.platform?.includes('shorts'));
shortsVideos.forEach(v => posts.push({
  platform: 'youtube_shorts',
  video_path: v.file_path,
  title: v.caption_shorts || data.product_title,
  description: `${data.product_title}\n\nGet it here: ${data.store_url}`,
  schedule: '17:00'
}));

return posts.map(p => ({ json: { ...p, product_id: data.product_id } }));
